import { useState } from 'react'
import Pagination from '@/components/ui/Pagination'

const Controlled = () => {
    const [page, setPage] = useState(60)

    const onPaginationChange = (val: number) => {
        setPage(val)
    }

    return (
        <div>
            <Pagination
                total={100}
                currentPage={page}
                onChange={onPaginationChange}
            />
        </div>
    )
}

export default Controlled

PageSize.code:
import { useState } from 'react'
import Pagination from '@/components/ui/Pagination'
import Select from '@/components/ui/Select'

type Option = {
    value: number
    label: string
}

const options: Option[] = [
    { value: 5, label: '5 / page' },
    { value: 10, label: '10 / page' },
    { value: 20, label: '20 / page' },
    { value: 50, label: '50 / page' },
]

const PageSize = () => {
    const [pageSize, setPageSize] = useState(options[0].value)

    const onPageSelect = ({ value }: Option) => {
        setPageSize(value)
    }

    return (
        <div className="flex items-center">
            <Pagination displayTotal pageSize={pageSize} total={100} />
            <div style={{ minWidth: 120 }}>
                <Select
                    size="sm"
                    isSearchable={false}
                    defaultValue={options[0]}
                    options={options}
                    onChange={selected => onPageSelect(selected as Option)}
                />
            </div>
        </div>
    )
}

export default PageSize

